import{_ as e,c as a,o,ag as l}from"./chunks/framework.DK1-H3E1.js";const u=JSON.parse('{"title":"注意力机制（Attention Mechanism）入门","description":"","frontmatter":{"order":12},"headers":[],"relativePath":"ai/attention-mechanism.md","filePath":"ai/attention-mechanism.md","lastUpdated":1772197851000}'),i={name:"ai/attention-mechanism.md"};function n(r,t,s,d,h,c){return o(),a("div",null,t[0]||(t[0]=[l('<h1 id="注意力机制-attention-mechanism-入门" tabindex="-1">注意力机制（Attention Mechanism）入门 <a class="header-anchor" href="#注意力机制-attention-mechanism-入门" aria-label="Permalink to &quot;注意力机制（Attention Mechanism）入门&quot;">​</a></h1><blockquote><p>📅 主题：从直觉到公式，理解 Transformer 的核心</p></blockquote><h2 id="一、为什么需要注意力机制" tabindex="-1">一、为什么需要注意力机制 <a class="header-anchor" href="#一、为什么需要注意力机制" aria-label="Permalink to &quot;一、为什么需要注意力机制&quot;">​</a></h2><p>在早期 NLP 模型（RNN/LSTM）里，模型需要按顺序处理文本，长距离依赖信息容易衰减。例如：</p><ul><li>句首的人名，可能影响句尾代词指代；</li><li>一段很长的上下文里，真正关键的信息只占几处。</li></ul><p><strong>注意力机制</strong>的核心思路是：<br> 在生成某个位置输出时，模型不平均看待所有输入，而是为不同位置分配不同权重，<strong>重点关注最相关的 token</strong>。</p><p>一句话：<strong>让模型“有重点地看上下文”。</strong></p><hr><h2 id="二、直观理解-查询、键、值" tabindex="-1">二、直观理解：查询、键、值 <a class="header-anchor" href="#二、直观理解-查询、键、值" aria-label="Permalink to &quot;二、直观理解：查询、键、值&quot;">​</a></h2><p>注意力通常用三组向量表示：</p><ul><li><strong>Q（Query）</strong>：当前要解决的问题（“我现在在找什么”）</li><li><strong>K（Key）</strong>：每个位置的索引标签（“我能提供什么”）</li><li><strong>V（Value）</strong>：每个位置真正携带的信息（“我的内容是什么”）</li></ul><p>流程可以理解为：</p><ol><li>用 Query 去和所有 Key 做匹配，得到相关性分数；</li><li>对分数做归一化（softmax）得到权重；</li><li>用这些权重对所有 Value 加权求和，得到当前输出。</li></ol><p>所以，注意力本质上是一个**可学习的软检索（soft retrieval）**过程。</p><hr><h2 id="三、核心公式-scaled-dot-product-attention" tabindex="-1">三、核心公式（Scaled Dot-Product Attention） <a class="header-anchor" href="#三、核心公式-scaled-dot-product-attention" aria-label="Permalink to &quot;三、核心公式（Scaled Dot-Product Attention）&quot;">​</a></h2><p>Transformer 中最常用的是缩放点积注意力：</p><p><code>Attention(Q, K, V) = softmax(QK^T / sqrt(d_k)) V</code></p><p>逐项解释：</p><ul><li><code>QK^T</code>：计算 Query 与每个 Key 的相似度（打分矩阵）</li><li><code>/ sqrt(d_k)</code>：缩放，避免维度高时点积过大导致 softmax 过于尖锐</li><li><code>softmax(...)</code>：转为概率分布（权重和为 1）</li><li><code>... V</code>：对 Value 做加权求和得到输出</li></ul><h3 id="为什么要除以-sqrt-d-k" tabindex="-1">为什么要除以 <code>sqrt(d_k)</code> <a class="header-anchor" href="#为什么要除以-sqrt-d-k" aria-label="Permalink to &quot;为什么要除以 `sqrt(d_k)`&quot;">​</a></h3><p>当向量维度 <code>d_k</code> 变大时，点积数值方差增大，softmax 可能进入饱和区，梯度变小、训练不稳定。<br> 缩放后数值更平稳，训练更容易。</p><hr><h2 id="四、自注意力-self-attention" tabindex="-1">四、自注意力（Self-Attention） <a class="header-anchor" href="#四、自注意力-self-attention" aria-label="Permalink to &quot;四、自注意力（Self-Attention）&quot;">​</a></h2><p>在 <strong>Self-Attention</strong> 中，Q、K、V 都来自同一序列（同一批 token 的线性变换）。<br> 这意味着每个 token 都可以和序列中所有 token 交互，得到“上下文增强”的表示。</p><p>优势：</p><ul><li>并行计算友好（相比 RNN 的时间步依赖）</li><li>能直接建模长距离依赖</li><li>每层都能重组上下文信息</li></ul><p>这也是 Transformer 能在长文本理解上表现强的重要原因。</p><hr><h2 id="五、多头注意力-multi-head-attention" tabindex="-1">五、多头注意力（Multi-Head Attention） <a class="header-anchor" href="#五、多头注意力-multi-head-attention" aria-label="Permalink to &quot;五、多头注意力（Multi-Head Attention）&quot;">​</a></h2><p>单头注意力只能在一个子空间里建模关系。<br> 多头注意力做法是：</p><ol><li>把 Q/K/V 投影到多个子空间（多个 head）；</li><li>每个 head 独立计算注意力；</li><li>拼接各 head 输出，再做线性变换。</li></ol><p>好处：</p><ul><li>不同 head 可以关注不同关系（语法、语义、位置、指代等）</li><li>表达能力更强</li><li>信息融合更丰富</li></ul><p>可以把它理解为：<strong>让模型从多个视角同时“看句子”。</strong></p><hr><h2 id="六、注意力与位置编码" tabindex="-1">六、注意力与位置编码 <a class="header-anchor" href="#六、注意力与位置编码" aria-label="Permalink to &quot;六、注意力与位置编码&quot;">​</a></h2><p>注意力本身对输入顺序不敏感（集合操作）。<br> 因此 Transformer 需要 <strong>Positional Encoding（位置编码）</strong> 提供顺序信息：</p><ul><li>告诉模型“谁在前谁在后”</li><li>帮助区分同词不同位置的语义作用</li></ul><p>没有位置编码，模型只能看到 token 集合，很难理解语序。</p><hr><h2 id="七、复杂度与工程挑战" tabindex="-1">七、复杂度与工程挑战 <a class="header-anchor" href="#七、复杂度与工程挑战" aria-label="Permalink to &quot;七、复杂度与工程挑战&quot;">​</a></h2><p>标准自注意力对长度为 <code>n</code> 的序列，计算复杂度和显存开销大致是 <code>O(n^2)</code>。<br> 序列越长，代价增长越快，这也是长上下文系统的核心瓶颈之一。</p><p>常见优化方向：</p><ul><li>稀疏注意力（只关注局部或选定位置）</li><li>线性注意力（近似 <code>O(n)</code>）</li><li>KV Cache（推理阶段复用历史 K/V）</li><li>分块/滑窗策略</li></ul><hr><h2 id="八、在-llm-应用中的意义" tabindex="-1">八、在 LLM 应用中的意义 <a class="header-anchor" href="#八、在-llm-应用中的意义" aria-label="Permalink to &quot;八、在 LLM 应用中的意义&quot;">​</a></h2><p>注意力机制直接影响：</p><ol><li><strong>上下文理解能力</strong>：能否抓住关键证据</li><li><strong>长文本表现</strong>：跨段引用、指代、总结能力</li><li><strong>工具调用与 Agent 决策</strong>：是否能从复杂上下文中选对步骤</li><li><strong>RAG 效果</strong>：注入多个检索片段时，模型能否聚焦关键片段</li></ol><p>因此，在 Prompt、RAG、Agent 场景中，理解注意力机制有助于解释模型“为什么答成这样”。</p><hr><h2 id="九、小结" tabindex="-1">九、小结 <a class="header-anchor" href="#九、小结" aria-label="Permalink to &quot;九、小结&quot;">​</a></h2><ol><li>注意力机制的本质是：<strong>按相关性对上下文做加权聚合</strong>。</li><li>核心公式是 <code>softmax(QK^T / sqrt(d_k))V</code>，缩放项用于稳定训练。</li><li>Self-Attention 让每个 token 与全局交互，多头机制让模型多视角建模。</li><li>注意力本身不含位置信息，需配合位置编码。</li><li>标准注意力有 <code>O(n^2)</code> 成本，长上下文场景需工程优化。</li></ol><p>掌握注意力机制，是理解 Transformer 与现代大模型行为的第一步。</p>',54)]))}const m=e(i,[["render",n]]);export{u as __pageData,m as default};
